import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Router, RouterModule } from '@angular/router';
import { AuthService } from '../services/auth.service'; // 👈 1. تأكدي من صحة مسار ملف الـ Service عندك

@Component({
  selector: 'app-login',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterModule],
  templateUrl: './login.component.html',
  styleUrls: ['./login.component.scss']
})
export class LoginComponent implements OnInit {
  loginForm!: FormGroup;
  selectedRole: 'patient' | 'doctor' | 'admin' = 'patient';
  showPassword = false;

  // 👈 2. حقنا الـ AuthService هنا جوه الـ Constructor
  constructor(
    private fb: FormBuilder, 
    private router: Router,
    private authService: AuthService 
  ) {}

  ngOnInit(): void {
    this.initForm();
  }

  initForm(): void {
    this.loginForm = this.fb.group({
      email: ['', [Validators.required, Validators.email]],
      password: ['', [Validators.required, Validators.minLength(6)]],
      rememberMe: [false]
    });
  }

  selectRole(role: 'patient' | 'doctor' | 'admin'): void {
    this.selectedRole = role;
  }

  togglePasswordVisibility(): void {
    this.showPassword = !this.showPassword;
  }

  // 🚀 3. دالة الـ Submit الحقيقية المربوطة بالـ Backend
  onSubmit(): void {
    if (this.loginForm.valid) {
      // تجهيز البيانات المرسلة للسيرفر شاملة الـ Role المختار
      const loginData = {
        email: this.loginForm.value.email,
        password: this.loginForm.value.password,
        role: this.selectedRole // 👈 بنبعت الـ role عشان السيرفر يتحقق منه
      };

      console.log('Sending login data to API:', loginData);

      // استدعاء دالة الـ login من الـ Service
      this.authService.login(loginData).subscribe({
        next: (response: any) => {
          console.log('Login successful, response:', response);

          // حفظ التوكن والـ role القادمين من الـ Backend في الـ LocalStorage
          // (تأكدي أن السيرفر بيرجع الـ token والـ role في الـ response)
          this.authService.storeSession(response.token, response.role || this.selectedRole);

          // 🔀 التوجيه الذكي المنفصل بناءً على الـ Role بعد نجاح الـ Login الحقيقي
          const userRole = response.role || this.selectedRole;

          if (userRole === 'admin') {
            this.router.navigate(['/admin-dashboard']);
          } else if (userRole === 'doctor') {
            this.router.navigate(['/doctor-dashboard']);
          } else if (userRole === 'patient') {
            this.router.navigate(['/home']);
          }
        },
        error: (err: any) => {
          console.error('Login failed:', err);
          // إظهار رسالة الخطأ القادمة من السيرفر أو رسالة افتراضية
          alert(err.error?.message || 'Login failed! Please check your credentials.');
        }
      });

    } else {
      // لو الفورم ناقص، نضئ الحقول بالأحمر لتنبيه المستخدم
      this.loginForm.markAllAsTouched();
    }
  }
}
